                    "order_id": state.get("order.id") ?? .null,
                    "customer_id": state.get("customer.id") ?? .null,
                    "amount": state.get("order.totalAmount") ?? .null,
                    "timestamp": .date(Date()),
                ]
            )
            try await runtime.checkpoint(label: "progress:0.3:L169:C0", state: state.snapshot())
        }

        await runtime.complete(reason: nil)
        return WorkflowResult(reason: nil, durationMS: await runtime.elapsedMS(), eventCount: await runtime.eventCount(), bindings: state.snapshot().asValues)
    }
}

public struct EscalateOrder: MeridianWorkflow {
    public let runtime: Runtime
    public let order: Order
    public let accountManager: AccountManager
    public let customer: Customer

    public init(runtime: Runtime, order: Order, accountManager: AccountManager, customer: Customer) {
        self.runtime = runtime
        self.order = order
        self.accountManager = accountManager
        self.customer = customer
    }

    public func run() async throws -> WorkflowResult {
        var state = State()
        state.bind("order", order)
        state.bind("accountManager", accountManager)
        state.bind("customer", customer)
        let __meridianResumeContext = await runtime.consumeResumeContext()
        if let __meridianResumeContext {
            state.restore(from: __meridianResumeContext.restoredState)
        }
        var __meridianResumeTarget = __meridianResumeContext?.lastCheckpointLabel
        func __meridianShouldRun(_ label: String) -> Bool {
            guard let target = __meridianResumeTarget else { return true }
            if target == label { __meridianResumeTarget = nil }
            return false
        }
        let constants = Constants()
        let instances = Instances()
        await runtime.workflowStarted(workflowName: "EscalateOrder", parameters: [:])

        if MeridianComparison.gt(state.get("order.totalAmount"), Value.from(constants.highValueThreshold)) {
            if __meridianShouldRun("progress:0.0.then.0:L14:C0") {
                try await runtime.wait(.approval(of: state.get("order") ?? .null, by: RoleRef(identifier: "account manager")))
                try await runtime.checkpoint(label: "progress:0.0.then.0:L14:C0", state: state.snapshot())
            }
        }

        if __meridianShouldRun("progress:0.1:L12:C0") {
            try await runtime.assert(!(MeridianComparison.gt(state.get("order.totalAmount"), state.get("customer.creditLimit"))), message: "A customer must not place an order whose total amount is more than their credit limit")
            try await runtime.checkpoint(label: "progress:0.1:L12:C0", state: state.snapshot())
        }
        if __meridianShouldRun("progress:0.2:L10:C0") {
            try await runtime.assert(!(MeridianComparison.eq(state.get("customer.status"), .string("suspended"))), message: "A customer with status suspended must not place orders")
            try await runtime.checkpoint(label: "progress:0.2:L10:C0", state: state.snapshot())
        }
        if __meridianShouldRun("progress:0.3:L34:C0") {
            try await runtime.emit(event: "`order.escalated` { order_id: the order's id, customer_id: the customer's id }", payload: [:])
            try await runtime.checkpoint(label: "progress:0.3:L34:C0", state: state.snapshot())
        }
        await runtime.complete(reason: "escalated")
        return WorkflowResult(reason: "escalated", durationMS: await runtime.elapsedMS(), eventCount: await runtime.eventCount(), bindings: state.snapshot().asValues)
    }
}

